def _int_range_arg(*, flag: str, minimum: int, maximum: int) -> Callable[[str], int]:
    def parse(value: str) -> int:
        try:
            parsed = int(value)
        except ValueError as exc:
            raise argparse.ArgumentTypeError(f"{flag} must be an integer.") from exc
        if parsed < minimum:
            raise argparse.ArgumentTypeError(f"{flag} must be >= {minimum}.")
        if parsed > maximum:
            raise argparse.ArgumentTypeError(f"{flag} must be <= {maximum}.")
        return parsed

    return parse


def _validate_int_range(
    payload: dict[str, Any],
    *,
    key: str,
    flag: str,
    minimum: int,
    maximum: int,
) -> None:
    raw = payload.get(key)
    if isinstance(raw, bool):
        raise ValueError(f"{flag} must be an integer.")
    try:
        value = int(raw)
    except (TypeError, ValueError) as exc:
        raise ValueError(f"{flag} must be an integer.") from exc
    if value < minimum:
        raise ValueError(f"{flag} must be >= {minimum} (got {value}). Retry with {flag} {minimum}.")
    if value > maximum:
        raise ValueError(f"{flag} must be <= {maximum} (got {value}). Retry with {flag} {maximum}.")
    payload[key] = value


def _add_web_research_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--query")
    parser.add_argument("--url")
    parser.add_argument(
        "--include", action="append", choices=kebab_choices(WEB_RESEARCH_INCLUDE_CHOICES)
    )
    parser.add_argument("--limit", type=int, default=5)
    parser.add_argument("--content-chars", type=int, default=800)
    parser.add_argument("--region", default="US")
    parser.add_argument("--timeout", type=int, default=45)
    parser.add_argument("--max-retries", type=int, default=3)


def _build_web_research_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    if args.query is not None:
        payload["query"] = args.query
    if args.url is not None:
        payload["url"] = args.url
    if args.include:
        payload["include"] = [dekebab(v) for v in args.include]
    payload.update(
        {
            "limit": args.limit,
            "content_chars": args.content_chars,
            "region": args.region,
            "timeout": args.timeout,
            "max_retries": args.max_retries,
        }
    )
    if not str(payload.get("query") or "").strip() and not str(payload.get("url") or "").strip():
        raise ValueError("research +web-research requires --query or --url.")
    return payload


