def _add_visual_analyze_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument(
        "--media",
        action="append",
        dest="media_urls",
        help=(
            "Image/video URL to analyze. For TikTok or signed CDN URLs that fail "
            "direct preparation, first run `asset +create --type media --url ...` "
            "and retry with the returned media_url or permanent_media_url."
        ),
    )
    parser.add_argument("--media-json")
    parser.add_argument("--media-file")
    parser.add_argument("--prompt", required=True)
    parser.add_argument("--context")
    parser.add_argument(
        "--model",
        help="Optional internal model override. Omit to use the default analysis model.",
    )
    parser.add_argument("--temperature", type=float)
    parser.add_argument("--max-output-tokens", type=int)


def _build_visual_analyze_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    if args.media_json:
        payload["media"] = _json_list(args.media_json, flag="--media-json")
    if args.media_file:
        media_payload = Path(args.media_file).read_text(encoding="utf-8")
        payload["media"] = _json_list(media_payload, flag="--media-file")
    if args.media_urls:
        payload["media"] = list(args.media_urls)
    if not payload.get("media"):
        raise ValueError(
            "research +visual-analyze requires --media, --media-json, or --media-file."
        )
    payload["prompt"] = args.prompt
    if args.context is not None:
        payload["context"] = args.context
    if args.model is not None:
        payload["model"] = args.model
    if args.temperature is not None:
        payload["temperature"] = args.temperature
    if args.max_output_tokens is not None:
        payload["max_output_tokens"] = args.max_output_tokens
    return payload


